// ShaderLab Custom — Sphere
uniform vec3  uColor;
uniform float uBright,uEdge;
uniform float uLodFade;
varying float vBlink;
varying float vPhase;
void main(){
  vec3  col=uColor*uBright;
  float alpha=1.0;
  float d=0.0;
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.25)discard;alpha=1.0-smoothstep(uEdge,0.25,d);}
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.464)discard;if(0.0>0.005&&d<0.0)discard;alpha=1.0-smoothstep(0.262,0.464,d);}
  col=uColor*(2.2*(0.301+vBlink*0.002));
  col=pow(max(col*vec3(0.89,0.93,0.95),vec3(0.0)),vec3(1.0/0.98));
  {float _gf=exp(-d*8.1)*0.51;col=mix(col,col*2.5,_gf*0.28);}
  alpha=pow(max(alpha,0.0),1.45)*0.15+0.0;
  if(alpha<=0.0)discard;
  gl_FragColor=vec4(col,clamp(alpha,0.0,1.0)*uLodFade);
}
